import React, { useState, useEffect } from 'react';
import Modal from '../components/Modal';
import api from '../services/api';

const LoanApprovals = () => {
  const [loans, setLoans] = useState([]);
  const [selected, setSelected] = useState(null);
  const [remarks, setRemarks] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchLoans();
  }, []);

  const fetchLoans = async () => {
    try {
      const res = await api.get('/admin/loans/pending');
      setLoans(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const approve = async (id) => {
    try {
      await api.post(`/admin/loan/${id}/approve`);
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
    } catch (err) {
      alert('Failed to approve loan');
    }
  }
  const reject = async (id) => {
    try {
      await api.post(`/admin/loan/${id}/reject`);
      setLoans(l => l.filter(x => x._id !== id));
      setSelected(null);
    } catch (err) {
      alert('Failed to reject loan');
    }
  }

  return (
    <div className="fade-in">
      <div className="flex-between mb-6">
        <h2 className="page-title">Loan Approvals</h2>
        <div className="card" style={{ padding: '8px 16px' }}>
          <span style={{ fontWeight: '500', color: 'var(--text-secondary)' }}>Pending Requests: <span style={{ color: 'var(--warning)' }}>{loans.length}</span></span>
        </div>
      </div>

      <div className="table-container">
        {loading ? (
          <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)' }}>Loading loans...</div>
        ) : loans.length === 0 ? (
          <div style={{ padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)' }}>No pending loan requests.</div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Member</th>
                <th>Amount</th>
                <th>Purpose</th>
                <th>Requested</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {loans.map(loan => (
                <tr key={loan._id}>
                  <td style={{ fontWeight: 500 }}>{loan.memberId?.fullName || 'N/A'}</td>
                  <td>${loan.amount?.toLocaleString()}</td>
                  <td>{loan.purpose || '-'}</td>
                  <td style={{ color: 'var(--text-secondary)' }}>{new Date(loan.requestDate).toLocaleDateString()}</td>
                  <td>
                    <span className="status-badge status-pending">{loan.status}</span>
                  </td>
                  <td>
                    <button className="btn btn-primary" style={{ padding: '0.25rem 0.75rem', fontSize: '0.75rem' }} onClick={() => setSelected(loan)}>Review</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {selected && (
        <Modal title={`Review Loan Application`} onClose={() => setSelected(null)}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
            <div>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Amount Requested</label>
              <div style={{ fontSize: '18px', fontWeight: 'bold', color: '#10b981' }}>{selected.amount.toLocaleString()} ETB</div>
            </div>
            <div>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Member ID</label>
              <div style={{ fontSize: '16px', fontWeight: '500' }}>{selected.memberId}</div>
            </div>
            <div style={{ gridColumn: 'span 2' }}>
              <label style={{ fontSize: '12px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Purpose</label>
              <div style={{ fontSize: '14px', color: '#374151', background: '#f9fafb', padding: '12px', borderRadius: '6px' }}>{selected.purpose}</div>
            </div>
          </div>

          <div style={{ marginBottom: 24 }}>
            <label style={{ fontSize: '14px', fontWeight: '500', display: 'block', marginBottom: '8px' }}>Admin Remarks</label>
            <textarea
              className="input"
              value={remarks}
              onChange={e => setRemarks(e.target.value)}
              placeholder="Enter reason for approval or rejection..."
              style={{ height: 100, width: '100%', padding: '12px', borderRadius: '6px', border: '1px solid #d1d5db' }}
            />
          </div>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button className="btn secondary" onClick={() => { reject(selected._id); }} style={{ background: '#fee2e2', color: '#ef4444', border: 'none' }}>Reject Application</button>
            <button className="btn" onClick={() => { approve(selected._id); }} style={{ background: '#10b981', color: '#fff', border: 'none' }}>Approve Application</button>
          </div>
        </Modal>
      )}

    </div>
  );
}
export default LoanApprovals;
